import React, {useEffect, useState} from 'react';
import {STRINGS} from "../../constants/strings";
import axios from "axios";
import {BASE_URL} from "../../constants/base_url";

function NewContact(props){
    const {userData, newContact} = props;
    const [inviteCode, setInviteCode] = useState("");

    const handleInviteCode = (event) => {
        setInviteCode(event.target.value);
    }

    const handleInviteContact = async (event) => {
        event.preventDefault();
        try {
            const token = localStorage.getItem("token");
            const response = await axios.post(`${BASE_URL}/invite`, {
                    inviteCode: inviteCode,
                },
                {
                    headers: {
                        Authorization: `Bearer ${token}`
                    }
                }
            );
        } catch (error) {
        }
    }
    useEffect(() => {
        //setAberto(isPreferencesEnable);
        const handleClickOutside = (event) => {
            if (aberto && menuRef.current && !menuRef.current.contains(event.target)) {
                onPreferencesChange(false);
                setAberto(false);
            }
            if(isEditingName && inputName.current && !inputName.current.contains(event.target)){
                setIsEditingName(false);
                handleEditingName(event);
            }
            if(isEditingDescription && inputDescription.current && !inputDescription.current.contains(event.target)){
                setIsEditingDescription(false);
                handleEditingDescription(event);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);
        return () => {
            document.removeEventListener("mousedown", handleClickOutside);
        };
    });

    return (
        <div className="newContact-container" hidden={newContact === false}>
            {userData && (
                <div className="newContact">
                    <h4 className="newContact-title">{STRINGS[userData.language].NewContact}</h4>
                    {/*<h5 className="newContact-invitation-code">{STRINGS[userData.language].InvitationCode}</h5>*/}
                    <form
                        className="newContactForm"
                        onSubmit={handleInviteContact}
                    >
                        <input
                            className="newContact-search"
                            type="text"
                            placeholder={STRINGS[userData.language].InvitationCode}
                            value={inviteCode}
                            onChange={handleInviteCode}
                        ></input>
                    </form>
                </div>
            )}
        </div>
    );
}

export default NewContact;
